import './CalendarMonthView.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../../../helpers/classnames';
import { convertUtcToTz, hasDateLimit } from '../../newUtils';
import type { CalendarMonthViewProps } from './CalendarMonthView.types';
import { MONTHS_ABBRS } from './constants';

export const CalendarMonthView: FC<CalendarMonthViewProps> = ({
	minDate,
	maxDate,
	viewDate,
	onSelectMonth,
	showStartPanel,
	timeZone,
}) => {
	// Переводим в локаль
	const userTz = convertUtcToTz(viewDate, timeZone);
	const currentYear = userTz?.getFullYear();
	const currentMonth = userTz?.getMonth();

	const minMonth = minDate && new Date(minDate.getFullYear(), minDate.getMonth());
	const maxMonth = maxDate && new Date(maxDate.getFullYear(), maxDate.getMonth());

	const isDisabledMonth = (monthIndex: number): boolean => {
		const checkedMonth = new Date(currentYear, monthIndex);

		return hasDateLimit(checkedMonth, minMonth, maxMonth);
	};

	const onClick = (monthIndex: number): void => {
		if (!isDisabledMonth(monthIndex)) {
			onSelectMonth(monthIndex);
			showStartPanel?.();
		}
	};

	return (
		<div className={'dsb_calendar-months'}>
			{MONTHS_ABBRS.map((month, monthIndex) => {
				const disabled = isDisabledMonth(monthIndex);
				const selected = monthIndex === currentMonth;

				return (
					<span
						data-testid={`month-${monthIndex}`}
						className={classNames('dsb_calendar-month', { disabled, selected })}
						onClick={(): void => onClick(monthIndex)}
						key={`month-${monthIndex}`}
					>
						{month}
					</span>
				);
			})}
		</div>
	);
};
